contracts/Escrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./Reputation.sol";
import "./ReferralRegistry.sol";
import "./SplitPayout.sol";

contract Escrow is Ownable, ReentrancyGuard {
  enum OrderStatus {
    ESCROWED,
    DELIVERED,
    RELEASED,
    REFUNDED,
    DISPUTED
  }

  struct Order {
    address buyer;
    address vendor;
    address reseller;
    uint256 amount;
    OrderStatus status;
    uint256 depositedAt;
    uint256 deliveredAt;
    uint256 releasedAt;
    string refundReason;
  }

  SplitPayout public splitPayout;
  Reputation public reputation;
  ReferralRegistry public referralRegistry;

  mapping(bytes32 => Order) public orders;
  uint256 public minOrderAmount = 0.01 ether;

  event EscrowDeposited(
    bytes32 indexed orderId,
    address indexed buyer,
    address indexed vendor,
    address reseller,
    uint256 amount
  );
  event DeliveryConfirmed(
    bytes32 indexed orderId,
    uint256 deliveredAt
  );
  event EscrowReleased(
    bytes32 indexed orderId,
    uint256 releaseAmount
  );
  event EscrowRefunded(
    bytes32 indexed orderId,
    address indexed buyer,
    uint256 amount,
    string reason
  );
  event DisputeOpened(
    bytes32 indexed orderId,
    address indexed initiator
  );
  event MinOrderAmountUpdated(uint256 newAmount);

  modifier orderExists(bytes32 orderId) {
    require(orders[orderId].buyer != address(0), "Order not found");
    _;
  }

  modifier onlyBuyer(bytes32 orderId) {
    require(msg.sender == orders[orderId].buyer, "Only buyer");
    _;
  }

  modifier onlyVendor(bytes32 orderId) {
    require(msg.sender == orders[orderId].vendor, "Only vendor");
    _;
  }

  modifier onlyBuyerOrVendor(bytes32 orderId) {
    require(
      msg.sender == orders[orderId].buyer ||
        msg.sender == orders[orderId].vendor,
      "Only buyer or vendor"
    );
    _;
  }

  constructor(
    address _splitPayout,
    address _reputation,
    address _referralRegistry
  ) Ownable(msg.sender) {
    require(_splitPayout != address(0), "Invalid split payout");
    require(_reputation != address(0), "Invalid reputation");
    require(_referralRegistry != address(0), "Invalid registry");

    splitPayout = SplitPayout(payable(_splitPayout));
    reputation = Reputation(_reputation);
    referralRegistry = ReferralRegistry(_referralRegistry);
  }

  function setMinOrderAmount(uint256 amount) external onlyOwner {
    minOrderAmount = amount;
    emit MinOrderAmountUpdated(amount);
  }

  function deposit(
    bytes32 orderId,
    address vendor,
    address reseller
  ) external payable nonReentrant {
    require(msg.value >= minOrderAmount, "Amount too small");
    require(vendor != address(0), "Invalid vendor");
    require(orders[orderId].buyer == address(0), "Order exists");

    Order storage order = orders[orderId];
    order.buyer = msg.sender;
    order.vendor = vendor;
    order.reseller = reseller;
    order.amount = msg.value;
    order.status = OrderStatus.ESCROWED;
    order.depositedAt = block.timestamp;

    emit EscrowDeposited(orderId, msg.sender, vendor, reseller, msg.value);
  }

  function confirmDelivery(bytes32 orderId)
    external
    orderExists(orderId)
    onlyBuyer(orderId)
    nonReentrant
  {
    Order storage order = orders[orderId];
    require(order.status == OrderStatus.ESCROWED, "Invalid state");
    require(order.deliveredAt == 0, "Already confirmed");

    order.status = OrderStatus.DELIVERED;
    order.deliveredAt = block.timestamp;

    emit DeliveryConfirmed(orderId, block.timestamp);
  }

  function release(bytes32 orderId)
    external
    orderExists(orderId)
    nonReentrant
  {
    Order storage order = orders[orderId];
    require(order.status == OrderStatus.DELIVERED, "Must be delivered");
    require(
      msg.sender == order.buyer || msg.sender == owner(),
      "Only buyer or owner"
    );
    require(order.releasedAt == 0, "Already released");

    order.status = OrderStatus.RELEASED;
    order.releasedAt = block.timestamp;

    // Execute split payout
    splitPayout.split(
      orderId,
      order.amount,
      order.reseller,
      order.vendor
    );

    emit EscrowReleased(orderId, order.amount);
  }

  function refund(
    bytes32 orderId,
    string calldata reason
  ) external orderExists(orderId) onlyBuyerOrVendor(orderId) nonReentrant {
    Order storage order = orders[orderId];
    require(
      order.status == OrderStatus.ESCROWED ||
        order.status == OrderStatus.DELIVERED,
      "Cannot refund"
    );
    require(order.releasedAt == 0, "Already released");

    order.status = OrderStatus.REFUNDED;
    order.refundReason = reason;

    // Refund to buyer
    (bool success, ) = order.buyer.call{value: order.amount}("");
    require(success, "Refund failed");

    // Debit vendor reputation on refund
    reputation.debitReputation(order.vendor, 1, reason);

    emit EscrowRefunded(orderId, order.buyer, order.amount, reason);
  }

  function dispute(bytes32 orderId, string calldata reason)
    external
    orderExists(orderId)
    onlyBuyerOrVendor(orderId)
  {
    Order storage order = orders[orderId];
    require(order.status != OrderStatus.RELEASED, "Cannot dispute");
    require(order.status != OrderStatus.REFUNDED, "Cannot dispute");

    order.status = OrderStatus.DISPUTED;
    order.refundReason = reason;

    emit DisputeOpened(orderId, msg.sender);
  }

  function getOrder(bytes32 orderId)
    external
    view
    returns (Order memory)
  {
    return orders[orderId];
  }

  function getOrderStatus(bytes32 orderId)
    external
    view
    returns (OrderStatus)
  {
    return orders[orderId].status;
  }

  receive() external payable {}
}

contracts/ReferralRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

contract ReferralRegistry is Ownable {
  mapping(address => address) public referrers;
  mapping(address => uint256) public referralCounts;
  mapping(address => bool) public registered;

  uint256 public maxChainDepth = 5;

  event ReferralRegistered(
    address indexed referrer,
    address indexed referree
  );
  event MaxChainDepthUpdated(uint256 newDepth);

  constructor() Ownable(msg.sender) {}

  function setMaxChainDepth(uint256 depth) external onlyOwner {
    require(depth > 0, "Depth must be positive");
    maxChainDepth = depth;
    emit MaxChainDepthUpdated(depth);
  }

  function registerReferral(address referrer, address referree) external {
    require(referrer != address(0), "Invalid referrer");
    require(referree != address(0), "Invalid referree");
    require(referrer != referree, "Cannot self-refer");
    require(!registered[referree], "Already registered");

    referrers[referree] = referrer;
    referralCounts[referrer]++;
    registered[referree] = true;

    emit ReferralRegistered(referrer, referree);
  }

  function getReferrer(address account) external view returns (address) {
    return referrers[account];
  }

  function getReferralChain(address account)
    external
    view
    returns (address[] memory)
  {
    address[] memory chain = new address[](maxChainDepth);
    uint256 count = 0;
    address current = account;

    while (current != address(0) && count < maxChainDepth) {
      current = referrers[current];
      if (current != address(0)) {
        chain[count] = current;
        count++;
      }
    }

    address[] memory result = new address[](count);
    for (uint256 i = 0; i < count; i++) {
      result[i] = chain[i];
    }

    return result;
  }

  function getReferralCount(address account) external view returns (uint256) {
    return referralCounts[account];
  }

  function isRegistered(address account) external view returns (bool) {
    return registered[account];
  }
}

contracts/Reputation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

contract Reputation is Ownable {
  struct ReputationEntry {
    int256 delta;
    string reason;
    uint256 timestamp;
  }

  mapping(address => int256) public reputation;
  mapping(address => ReputationEntry[]) public auditLog;
  mapping(address => bool) public authorizedCallers;

  uint256 public minReputationThreshold = 10;
  uint256 public maxReputationCap = 1000;

  event ReputationCredited(
    address indexed vendor,
    uint256 amount,
    string reason,
    int256 newScore
  );
  event ReputationDebited(
    address indexed vendor,
    uint256 amount,
    string reason,
    int256 newScore
  );
  event GenuinessStatusChanged(address indexed vendor, bool isGenuine);
  event AuthorizationChanged(address indexed caller, bool authorized);
  event ThresholdUpdated(uint256 newThreshold);

  modifier onlyAuthorized() {
    require(
      authorizedCallers[msg.sender] || msg.sender == owner(),
      "Not authorized"
    );
    _;
  }

  constructor() Ownable(msg.sender) {}

  function setAuthorized(address caller, bool authorized) external onlyOwner {
    authorizedCallers[caller] = authorized;
    emit AuthorizationChanged(caller, authorized);
  }

  function setMinReputationThreshold(uint256 threshold) external onlyOwner {
    minReputationThreshold = threshold;
    emit ThresholdUpdated(threshold);
  }

  function creditReputation(
    address vendor,
    uint256 amount,
    string calldata reason
  ) external onlyAuthorized {
    require(vendor != address(0), "Invalid vendor");
    require(amount > 0, "Amount must be positive");

    int256 delta = int256(amount);
    int256 newScore = reputation[vendor] + delta;

    if (newScore > int256(maxReputationCap)) {
      newScore = int256(maxReputationCap);
    }

    int256 actualDelta = newScore - reputation[vendor];
    reputation[vendor] = newScore;

    auditLog[vendor].push(
      ReputationEntry({delta: actualDelta, reason: reason, timestamp: block.timestamp})
    );

    bool wasGenuine = reputation[vendor] - actualDelta >=
      int256(minReputationThreshold);
    bool nowGenuine = newScore >= int256(minReputationThreshold);
    if (wasGenuine != nowGenuine) {
      emit GenuinessStatusChanged(vendor, nowGenuine);
    }

    emit ReputationCredited(vendor, amount, reason, newScore);
  }

  function debitReputation(
    address vendor,
    uint256 amount,
    string calldata reason
  ) external onlyAuthorized {
    require(vendor != address(0), "Invalid vendor");
    require(amount > 0, "Amount must be positive");

    int256 delta = -int256(amount);
    int256 newScore = reputation[vendor] + delta;

    if (newScore < 0) {
      newScore = 0;
    }

    int256 actualDelta = newScore - reputation[vendor];
    reputation[vendor] = newScore;

    auditLog[vendor].push(
      ReputationEntry({delta: actualDelta, reason: reason, timestamp: block.timestamp})
    );

    bool wasGenuine = reputation[vendor] - actualDelta >=
      int256(minReputationThreshold);
    bool nowGenuine = newScore >= int256(minReputationThreshold);
    if (wasGenuine != nowGenuine) {
      emit GenuinessStatusChanged(vendor, nowGenuine);
    }

    emit ReputationDebited(vendor, amount, reason, newScore);
  }

  function getReputation(address vendor) external view returns (int256) {
    return reputation[vendor];
  }

  function isGenuine(address vendor) external view returns (bool) {
    return reputation[vendor] >= int256(minReputationThreshold);
  }

  function getAuditLogLength(address vendor) external view returns (uint256) {
    return auditLog[vendor].length;
  }

  function getAuditLogEntry(
    address vendor,
    uint256 index
  ) external view returns (ReputationEntry memory) {
    require(index < auditLog[vendor].length, "Index out of bounds");
    return auditLog[vendor][index];
  }
}

